request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?task ?taskName ?initPartRef ?loopType WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_3772a4c8_337f_4a64_a2fc_de2aebea6f5b> .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bboExt:initiatingParticipantRef ?initPartRef . }
  OPTIONAL { ?task bboExt:loopType ?loopType . }
}
ORDER BY ?taskName
LIMIT 30

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?gwName ?gwDir ?type WHERE {
  ?gw a ?type .
  FILTER(?type IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  ?gw tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_3772a4c8_337f_4a64_a2fc_de2aebea6f5b> .
  OPTIONAL { ?gw bbo:name ?gwName . }
  OPTIONAL { ?gw bboExt:gatewayDirection ?gwDir . }
}
LIMIT 20

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?msg ?msgName ?sourceRef ?targetRef WHERE {
  ?msg a bboExt:MessageFlow .
  ?msg tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_3772a4c8_337f_4a64_a2fc_de2aebea6f5b> .
  OPTIONAL { ?msg bbo:name ?msgName . }
  OPTIONAL { ?msg bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?msg bboExt:targetRef ?targetRef . }
}
LIMIT 30

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gw ?gwName ?gwDir (COUNT(?outFlow) as ?outFlows) (COUNT(?inFlow) as ?inFlows) WHERE {
  ?gw a bboExt:ParallelGateway .
  ?gw tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_3772a4c8_337f_4a64_a2fc_de2aebea6f5b> .
  OPTIONAL { ?gw bbo:name ?gwName . }
  OPTIONAL { ?gw bboExt:gatewayDirection ?gwDir . }

  OPTIONAL {
    ?outFlow a bbo:SequenceFlow .
    ?outFlow bbo:has_sourceRef ?gw .
  }
  OPTIONAL {
    ?inFlow a bbo:SequenceFlow .
    ?inFlow bbo:has_targetRef ?gw .
  }
}
GROUP BY ?gw ?gwName ?gwDir
ORDER BY ?gwDir
